3. public record Product(string Sku, string Name, decimal Price);
4. 
5. public class ProductCatalog
6. {
7.     private readonly IProductStore _store;
8.     public ProductCatalog(IProductStore store) => _store = store;
9. 
10.     public void AddProduct(Product p) => _store.Save(p);
11.     public Product? GetProduct(string sku) => _store.FindBySku(sku);
12.     public void UpdatePrice(string sku, decimal newPrice)
13.     {
14.         var p = _store.FindBySku(sku) ?? throw new KeyNotFoundException(sku);
15.         _store.Save(p with { Price = newPrice });
16.     }
17.     public void RemoveProduct(string sku) => _store.Delete(sku);
18.     public List<Product> Search(string query) => _store.FindByName(query);
19.     public List<Product> GetAll() => _store.GetAll();
20.     public int GetProductCount() => _store.GetAll().Count;
21.     public void ApplyBulkDiscount(decimal fraction)
22.     {
23.         foreach (var p in _store.GetAll())
24.             _store.Save(p with { Price = p.Price * (1 - fraction) });
25.     }
26.     public string ExportToCsv() =>
27.         string.Join("\n", _store.GetAll().Select(p => $"{p.Sku},{p.Name},{p.Price}"));
28.     public void ImportFromCsv(string csv)
29.     {
30.         foreach (var line in csv.Split('\n'))
31.         {
32.             var parts = line.Split(',');
33.             _store.Save(new Product(parts[0], parts[1], decimal.Parse(parts[2])));
34.         }
35.     }
36. }
37. 
38. public interface IProductStore
39. {
40.     void Save(Product p);
41.     void Delete(string sku);
42.     Product? FindBySku(string sku);
43.     List<Product> FindByName(string query);
44.     List<Product> GetAll();
45. }
46. 
47. public class InMemoryStore : IProductStore
48. {
49.     private readonly Dictionary<string, Product> _products = new();
50. 
