52.     public void Delete(string sku) => _products.Remove(sku);
53.     public Product? FindBySku(string sku) => _products.GetValueOrDefault(sku);
54.     public List<Product> FindByName(string query) =>
55.         _products.Values.Where(p => p.Name.Contains(query, StringComparison.OrdinalIgnoreCase)).ToList();
56.     public List<Product> GetAll() => _products.Values.ToList();
57. }
58.

